scripts.script:
// No per-series colors, no foreColor, no grid.borderColor: the chart reads the
// --apx-* tokens from the cascade. theme.follow:'os' additionally tracks the
// operating system's light/dark setting with zero JS.
// Shared by the vanilla-js, React and Vue builds: the accent tokens the
// Shuffle button cycles through at runtime.
var ACCENTS = ['#e11d48', '#0e9d9a', '#d97706', '#7c3aed', '#4f46e5']

html:
Toggle light / dark Shuffle accent token
{{ charts[0] }}
Every color here comes from CSS --apx-* tokens (--apx-accent, --apx-fore, --apx-grid, --apx-surface) defined once in the stylesheet. The chart config sets no colors at all. The first button flips a class that swaps the token values; with theme: { follow: 'os' } the chart also tracks the OS prefers-color-scheme automatically, no JS required. Shuffle accent token changes only the CSS variable at runtime and calls chart.refreshTokens(), which re-reads the cascade and re-renders: the path for design-system theme switches that are not an OS color-scheme flip.

chart.options:
chart: {
  id: 'facetTokensChart',
  height: 400,
  type: 'area',
  fontFamily: 'sans-serif',
  animations: { enabled: true },
  toolbar: { show: false },
},
theme: {
  follow: 'os',
},
stroke: { curve: 'smooth', width: 2 },
fill: { type: 'gradient', gradient: { opacityFrom: 0.35, opacityTo: 0.05 } },
dataLabels: { enabled: false },
title: {
  text: 'Weekly active users',
  align: 'left',
},
subtitle: {
  text: 'Colors come entirely from CSS --apx-* design tokens',
  align: 'left',
},
xaxis: {
  type: 'category',
  categories: ['Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat', 'Sun'],
},
grid: {
  borderColor: '#e0e0e0',
},

vanilla-js-script:
// ACCENTS lives in the shared head script so all three builds cycle the same set.
var root = document.documentElement
var stateEl = document.getElementById('state')

function currentMode() {
  return root.classList.contains('apx-dark') ? 'dark' : 'light'
}
function syncState() {
  stateEl.textContent = 'Current: ' + currentMode()
}
syncState()

document.getElementById('toggle').addEventListener('click', function () {
  root.classList.toggle('apx-dark')
  var mode = currentMode()
  // Re-render so the chart re-reads the (now swapped) --apx-* token values and
  // applies the matching built-in mode. With follow:'os' this happens on its
  // own when the OS setting changes.
  chart.updateOptions({ theme: { mode: mode } })
  syncState()
})

var accentIdx = -1
document.getElementById('shuffle').addEventListener('click', function () {
  accentIdx = (accentIdx + 1) % ACCENTS.length
  // A pure token change: no chart option differs, so updateOptions({}) would
  // be memoized away. refreshTokens() re-reads the CSS cascade and re-renders.
  root.style.setProperty('--apx-accent', ACCENTS[accentIdx])
  chart.refreshTokens()
})

react-script:
React.useEffect(() => {
  // The react-apexcharts wrapper owns the render, so reach the live instance by
  // its chart.id at event time. The buttons live in the html block, so they are
  // in the DOM when this effect runs. (ACCENTS lives in the shared head script.)
  const root = document.documentElement
  const stateEl = document.getElementById('state')
  let accentIdx = -1

  const currentMode = () => (root.classList.contains('apx-dark') ? 'dark' : 'light')
  const syncState = () => { stateEl.textContent = 'Current: ' + currentMode() }
  syncState()

  const onToggle = () => {
    root.classList.toggle('apx-dark')
    const chart = ApexCharts.getChartByID('facetTokensChart')
    if (chart) chart.updateOptions({ theme: { mode: currentMode() } })
    syncState()
  }
  const onShuffle = () => {
    accentIdx = (accentIdx + 1) % ACCENTS.length
    root.style.setProperty('--apx-accent', ACCENTS[accentIdx])
    const chart = ApexCharts.getChartByID('facetTokensChart')
    if (chart) chart.refreshTokens()
  }

  const toggleBtn = document.getElementById('toggle')
  const shuffleBtn = document.getElementById('shuffle')
  toggleBtn.addEventListener('click', onToggle)
  shuffleBtn.addEventListener('click', onShuffle)

  return () => {
    toggleBtn.removeEventListener('click', onToggle)
    shuffleBtn.removeEventListener('click', onShuffle)
  }
}, [])

vue-script:
mounted: function () {
  // The vue-apexcharts wrapper owns the render, so reach the live instance by
  // its chart.id at event time. (ACCENTS lives in the shared head script.)
  var root = document.documentElement
  var stateEl = document.getElementById('state')
  var accentIdx = -1

  function currentMode() {
    return root.classList.contains('apx-dark') ? 'dark' : 'light'
  }
  function syncState() {
    stateEl.textContent = 'Current: ' + currentMode()
  }
  syncState()

  var onToggle = function () {
    root.classList.toggle('apx-dark')
    var chart = ApexCharts.getChartByID('facetTokensChart')
    if (chart) chart.updateOptions({ theme: { mode: currentMode() } })
    syncState()
  }
  var onShuffle = function () {
    accentIdx = (accentIdx + 1) % ACCENTS.length
    root.style.setProperty('--apx-accent', ACCENTS[accentIdx])
    var chart = ApexCharts.getChartByID('facetTokensChart')
    if (chart) chart.refreshTokens()
  }

  var toggleBtn = document.getElementById('toggle')
  var shuffleBtn = document.getElementById('shuffle')
  toggleBtn.addEventListener('click', onToggle)
  shuffleBtn.addEventListener('click', onShuffle)

  this._toggleBtn = toggleBtn
  this._shuffleBtn = shuffleBtn
  this._onToggle = onToggle
  this._onShuffle = onShuffle
},
beforeDestroy: function () {
  if (this._toggleBtn) this._toggleBtn.removeEventListener('click', this._onToggle)
  if (this._shuffleBtn) this._shuffleBtn.removeEventListener('click', this._onShuffle)
},
